import { useEffect, useMemo, useState } from 'react';
import { supabase } from './services/supabase';
import { Auth } from './components/Auth';
import { format } from 'date-fns';
import { Plus } from 'lucide-react';
import { useTasks } from './hooks/useTasks';
import { useHabits } from './hooks/useHabits';
import { useObjectives } from './hooks/useObjectives';
import { useDayClosure } from './hooks/useDayClosure';
import { useGamification } from './hooks/useGamification';
import { useSync } from './hooks/useSync';
import { useUIStore } from './store/useUIStore';
import { useTheme } from './context/ThemeContext';
import { Task, Habit, Objective } from './types';
import { cn } from './utils';
import { shouldHabitOccurOnDate, calculateObjectiveProgress } from './utils/habitUtils';
import { TaskModal } from './components/TaskModal';
import { HabitModal } from './components/HabitModal';
import { ObjectiveModal } from './components/ObjectiveModal';
import { CloseDayModal } from './components/CloseDayModal';
import { OnboardingWizard } from './components/OnboardingWizard';
import { Toast } from './components/Toast';
import confetti from 'canvas-confetti';
import { soundManager } from './utils/sounds';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { ViewHeader } from './components/ViewHeader';
import { ViewManager } from './components/ViewManager';
import { useUserStore } from './store/useUserStore';
import { Session } from '@supabase/supabase-js';
import { migrationService } from './services/migrationService';
import { dbService } from './services/dbService';

export default function App() {
  const [session, setSession] = useState<Session | null>(null);
  const [isMigrating, setIsMigrating] = useState(false);

  useEffect(() => {
    supabase?.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase!.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const { viewMode, setViewMode, isFocusMode, setIsFocusMode, toast, setToast, closeToast } =
    useUIStore();
  const { theme, toggleTheme } = useTheme();

  const handleLevelUp = (level: number) => {
    soundManager.playSuccess();
    confetti({
      particleCount: 150,
      spread: 70,
      origin: { y: 0.6 },
      colors: ['#F27D26', '#E6E6E6', '#141414'],
    });
    setToast({
      isOpen: true,
      title: '┬íNivel Completado!',
      message: `Has alcanzado el Nivel ${level}. Sigue as├¡, Junior.`,
    });
  };

  const {
    stats,
    addExp,
    completeOnboarding,
    loadProfile,
    // userId, // We'll use session.user.id
    setUserId,
    closedDays,
    isDayClosed,
    closeDay,
    calculateStreak,
    weeklyInsights,
  } = {
    ...useGamification({ onLevelUp: handleLevelUp }),
    ...useDayClosure(),
    ...useUserStore(),
  };

  const { loadHabits, loadLogs, habits, logs, addHabit, updateHabit, toggleHabitLog: _toggleHabitLog } = useHabits();
  const { loadObjectives, objectives, addObjective, updateObjective } = useObjectives();
  const { loadTasks, tasks, addTask, updateTask, deleteTask, toggleTask } = useTasks();
  const { isSyncing, isRestoring, handleSync, handleRestore } = useSync();

  useEffect(() => {
    if (session?.user && !isMigrating) {
      const uid = session.user.id;
      setUserId(uid);

      const initData = async () => {
        try {
          // Check if profile exists and has data
          const profile = await dbService.getProfile(uid);

          if (!profile || (profile.total_exp === 0 && !profile.onboarding_completed)) {
            // Check if local data exists
            const hasLocalData = !!localStorage.getItem('iterum_user_storage');

            if (hasLocalData) {
              setIsMigrating(true);
              setToast({
                isOpen: true,
                title: 'Migrando Datos...',
                message: 'Estamos moviendo tu progreso local a la nube.',
              });
              await migrationService.migrateLocalToCloud(uid);
              setToast({
                isOpen: true,
                title: '┬íMigraci├│n Exitosa!',
                message: 'Tus datos ahora est├ín seguros en la nube.',
              });
              setIsMigrating(false);
            }
          }

          loadProfile(uid);
          loadHabits(uid);
          loadLogs(uid);
          loadTasks(uid);
          loadObjectives(uid);
        } catch (error) {
          console.error('Initialization error:', error);
          loadProfile(uid);
          loadHabits(uid);
          loadLogs(uid);
          loadTasks(uid);
          loadObjectives(uid);
        }
      };

      initData();
    } else if (!session) {
      setUserId(null);
    }
  }, [session, setUserId, loadProfile, loadHabits, loadLogs, loadTasks, loadObjectives, isMigrating, setToast]);

  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isHabitModalOpen, setIsHabitModalOpen] = useState(false);
  const [isObjectiveModalOpen, setIsObjectiveModalOpen] = useState(false);
  const [isCloseDayModalOpen, setIsCloseDayModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [taskToEdit, setTaskToEdit] = useState<Task | undefined>(undefined);
  const [habitToEdit, setHabitToEdit] = useState<Habit | undefined>(undefined);
  const [objectiveToEdit, setObjectiveToEdit] = useState<Objective | undefined>(undefined);
  const [searchQuery, setSearchQuery] = useState('');

  const handleToggleMilestone = (objectiveId: string, milestoneId: string) => {
    const objective = objectives.find((o) => o.id === objectiveId);
    if (!objective || !objective.milestones) return;

    const updatedMilestones = objective.milestones.map((m) =>
      m.id === milestoneId
        ? { ...m, completed: !m.completed, completedAt: !m.completed ? new Date() : undefined }
        : m,
    );

    updateObjective(objectiveId, { milestones: updatedMilestones });

    // Award EXP for completing a milestone
    const milestone = objective.milestones.find((m) => m.id === milestoneId);
    if (milestone && !milestone.completed) {
      addExp(25, 'discipline');
      soundManager.playSuccess();
      setToast({
        isOpen: true,
        title: '┬íHito Alcanzado!',
        message: `Has completado: ${milestone.title}`,
      });
    }
  };

  const toggleHabitLog = (habitId: string, date: Date, value?: number, note?: string) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    const existingLog = logs.find((l) => l.habitId === habitId && l.date === dateStr);

    // Award EXP for first check-in or note
    if (!existingLog) {
      addExp(10, 'discipline');
      soundManager.playPop();
    } else if (note && !existingLog.note) {
      addExp(8, 'consistency');
    }

    _toggleHabitLog(habitId, date, value, note);
  };

  const objectivesWithProgress = useMemo(() => {
    return objectives.map((obj) => ({
      ...obj,
      currentValue: calculateObjectiveProgress(obj, habits, logs),
    }));
  }, [objectives, habits, logs]);

  const handleDateSelect = (date: Date) => {
    setSelectedDate(date);
    setTaskToEdit(undefined);
    setIsTaskModalOpen(true);
  };

  const handleEditTask = (task: Task) => {
    setTaskToEdit(task);
    setIsTaskModalOpen(true);
  };

  const handleEditHabit = (habit: Habit) => {
    setHabitToEdit(habit);
    setIsHabitModalOpen(true);
  };

  const handleEditObjective = (objective: Objective) => {
    setObjectiveToEdit(objective);
    setIsObjectiveModalOpen(true);
  };

  const handleCloseTaskModal = () => {
    setIsTaskModalOpen(false);
    setTimeout(() => setTaskToEdit(undefined), 200);
  };

  const handleCloseHabitModal = () => {
    setIsHabitModalOpen(false);
    setTimeout(() => setHabitToEdit(undefined), 200);
  };

  const handleCloseObjectiveModal = () => {
    setIsObjectiveModalOpen(false);
    setTimeout(() => setObjectiveToEdit(undefined), 200);
  };

  const handleOpenCloseDayModal = () => {
    setIsCloseDayModalOpen(true);
  };

  const handleConfirmCloseDay = async () => {
    const result = await closeDay(new Date(), habits, logs, tasks, updateTask, addTask);
    if (result) {
      addExp(25, 'consistency');
    }
    return result;
  };

  const handleSaveTask = (
    taskData: Omit<Task, 'id' | 'completed' | 'createdAt'> & { habitData?: any; objectiveData?: any },
  ) => {
    if (taskToEdit) {
      updateTask(taskToEdit.id, taskData);
    } else if (taskData.type === 'habit') {
      addHabit({
        name: taskData.title,
        description: taskData.description,
        frequency: taskData.habitData?.frequency || 'daily',
        type: taskData.habitData?.type || 'yesno',
        targetValue: taskData.habitData?.targetValue,
        unit: taskData.habitData?.unit,
        color: taskData.color,
      });
    } else if (taskData.type === 'objective') {
      addObjective({
        title: taskData.title,
        description: taskData.description,
        targetValue: taskData.objectiveData?.targetValue || 100,
        currentValue: 0,
        unit: taskData.objectiveData?.unit || '%',
        deadline: taskData.objectiveData?.deadline,
        color: taskData.color,
      });
    } else {
      addTask(taskData);
    }
  };

  const handleSaveHabit = (habitData: Omit<Habit, 'id' | 'isActive' | 'createdAt'>) => {
    if (habitToEdit) {
      updateHabit(habitToEdit.id, habitData);
    } else {
      addHabit(habitData);
    }
  };

  const handleSaveObjective = (objectiveData: Omit<Objective, 'id' | 'isActive' | 'createdAt'>) => {
    if (objectiveToEdit) {
      updateObjective(objectiveToEdit.id, objectiveData);
    } else {
      addObjective(objectiveData);
    }
  };

  const filteredTasks = tasks.filter(
    (t) =>
      t.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      t.description?.toLowerCase().includes(searchQuery.toLowerCase()),
  );

  const filteredHabits = habits.filter(
    (h) =>
      h.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      h.description?.toLowerCase().includes(searchQuery.toLowerCase()),
  );

  const filteredObjectives = objectivesWithProgress.filter(
    (o) =>
      o.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      o.description?.toLowerCase().includes(searchQuery.toLowerCase()),
  );

  const todayHabits = habits.filter(
    (h) => h.isActive && shouldHabitOccurOnDate(h.frequency, new Date()),
  );

  const streak = calculateStreak();

  if (!session) {
    return (
      <div
        className={cn(
          'bg-bg-primary text-text-primary min-h-screen font-sans transition-all duration-700 dark:bg-[--dark-bg-primary] dark:text-[--dark-text-primary]',
        )}
      >
        <Auth />
      </div>
    );
  }

  return (
    <div
      className={cn(
        'bg-bg-primary text-text-primary min-h-screen font-sans transition-all duration-700 dark:bg-[--dark-bg-primary] dark:text-[--dark-text-primary]',
        isFocusMode && 'bg-black text-white/90',
      )}
    >
      {/* Focus Mode Overlay */}
      {isFocusMode && (
        <div className="pointer-events-none fixed inset-0 z-[100] bg-black opacity-40 mix-blend-multiply" />
      )}

      {/* Header */}
      {!isFocusMode && (
        <Header
          viewMode={viewMode}
          setViewMode={setViewMode}
          searchQuery={searchQuery}
          setSearchQuery={setSearchQuery}
          theme={theme}
          toggleTheme={toggleTheme}
          onSignOut={async () => {
            await supabase!.auth.signOut();
            setSession(null);
          }}
          onNewObjective={() => {
            setObjectiveToEdit(undefined);
            setIsObjectiveModalOpen(true);
          }}
          onCapture={() => {
            setSelectedDate(new Date());
            setTaskToEdit(undefined);
            setIsTaskModalOpen(true);
          }}
        />
      )}

      {/* Main Content */}
      <main className="mx-auto max-w-6xl px-6 py-10">
        <div className="flex flex-col gap-10">
          {/* View Header */}
          <ViewHeader
            viewMode={viewMode}
            streak={streak}
            isDayClosed={isDayClosed}
            handleOpenCloseDayModal={handleOpenCloseDayModal}
            filteredTasks={filteredTasks}
            closedDays={closedDays}
            setIsObjectiveModalOpen={setIsObjectiveModalOpen}
            setObjectiveToEdit={setObjectiveToEdit}
          />

          {/* Dynamic View Rendering */}
          <div className="grid grid-cols-1 gap-10 lg:grid-cols-12">
            <ViewManager
              viewMode={viewMode}
              filteredHabits={filteredHabits}
              filteredObjectives={filteredObjectives}
              filteredTasks={filteredTasks}
              todayHabits={todayHabits}
              habits={habits}
              logs={logs}
              tasks={tasks}
              weeklyInsights={weeklyInsights}
              stats={stats}
              toggleHabitLog={toggleHabitLog}
              handleEditHabit={handleEditHabit}
              handleEditObjective={handleEditObjective}
              handleToggleMilestone={handleToggleMilestone}
              handleEditTask={handleEditTask}
              toggleTask={toggleTask}
              deleteTask={deleteTask}
              handleDateSelect={handleDateSelect}
            />

            <Sidebar
              stats={stats}
              objectivesWithProgress={objectivesWithProgress}
              objectives={objectives}
              setViewMode={setViewMode}
              isFocusMode={isFocusMode}
              setIsFocusMode={setIsFocusMode}
              isSyncing={isSyncing}
              isRestoring={isRestoring}
              handleSync={handleSync}
              handleRestore={handleRestore}
              habits={habits}
              logs={logs}
              tasks={tasks}
              closedDays={closedDays}
              weeklyInsights={weeklyInsights}
            />
          </div>
        </div>
      </main>

      {/* Modals */}
      <TaskModal
        isOpen={isTaskModalOpen}
        onClose={handleCloseTaskModal}
        onSave={handleSaveTask}
        initialDate={selectedDate}
        taskToEdit={taskToEdit}
      />

      <HabitModal
        isOpen={isHabitModalOpen}
        onClose={handleCloseHabitModal}
        onSave={handleSaveHabit}
        habitToEdit={habitToEdit}
      />

      <ObjectiveModal
        isOpen={isObjectiveModalOpen}
        onClose={handleCloseObjectiveModal}
        onSave={handleSaveObjective}
        objectiveToEdit={objectiveToEdit}
      />

      <CloseDayModal
        isOpen={isCloseDayModalOpen}
        onClose={() => setIsCloseDayModalOpen(false)}
        onConfirm={handleConfirmCloseDay}
      />

      {/* Mobile FAB */}
      <div className="fixed right-6 bottom-8 z-40 sm:hidden">
        <button
          onClick={() => {
            setSelectedDate(new Date());
            setTaskToEdit(undefined);
            setIsTaskModalOpen(true);
          }}
          className="bg-accent text-bg-primary flex h-16 w-16 items-center justify-center rounded-full shadow-2xl transition-transform active:scale-90"
        >
          <Plus className="h-8 w-8" />
        </button>
      </div>

      {!stats.onboardingCompleted && <OnboardingWizard onComplete={completeOnboarding} />}

      <Toast
        isOpen={toast.isOpen}
        onClose={closeToast}
        title={toast.title}
        message={toast.message}
      />
    </div>
  );
}

import React, { useState } from 'react';
import { supabase } from '../services/supabase';
import { Mail, Lock, User, Github, Chrome, ArrowRight, Loader2, Info } from 'lucide-react';
import { cn } from '../utils';
import { motion, AnimatePresence } from 'motion/react';

interface AuthProps {
  onSuccess?: () => void;
}

export function Auth({ onSuccess }: AuthProps) {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isLogin) {
        const { error } = await supabase!.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      } else {
        const { error } = await supabase!.auth.signUp({
          email,
          password,
          options: {
            data: {
              full_name: name,
            },
          },
        });
        if (error) throw error;
        setError('Check your email for the confirmation link!');
      }
      if (isLogin && onSuccess) onSuccess();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleSocialLogin = async (provider: 'google' | 'github') => {
    try {
      const { error } = await supabase!.auth.signInWithOAuth({
        provider,
        options: {
          redirectTo: window.location.origin,
        },
      });
      if (error) throw error;
    } catch (err: any) {
      setError(err.message);
    }
  };

  return (
    <div className="flex min-h-[80vh] items-center justify-center p-4">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-bg-primary/80 border-border-subtle w-full max-w-md overflow-hidden rounded-[40px] border shadow-2xl backdrop-blur-2xl dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-primary]/80"
      >
        <div className="p-10">
          <div className="mb-10 text-center">
            <div className="bg-accent mb-6 inline-flex h-16 w-16 items-center justify-center rounded-[24px] shadow-2xl shadow-accent/20">
              <User className="text-bg-primary h-8 w-8" />
            </div>
            <h2 className="text-3xl font-bold tracking-tight">
              {isLogin ? 'Bienvenido a ITERUM' : '├Ünete a la Forja'}
            </h2>
            <p className="text-text-muted mt-2 text-sm">
              {isLogin ? 'Tu progreso te espera.' : 'Comienza tu camino a la maestr├¡a.'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            <AnimatePresence mode="wait">
              {!isLogin && (
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  exit={{ opacity: 0, height: 0 }}
                  className="space-y-2"
                >
                  <label className="text-text-muted ml-4 text-[10px] font-bold tracking-widest uppercase">
                    Nombre Completo
                  </label>
                  <div className="relative">
                    <User className="text-text-muted absolute top-1/2 left-4 h-4 w-4 -translate-y-1/2" />
                    <input
                      type="text"
                      required
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      className="iterum-input w-full pl-12"
                      placeholder="Marcus Aurelius"
                    />
                  </div>
                </motion.div>
              )}
            </AnimatePresence>

            <div className="space-y-2">
              <label className="text-text-muted ml-4 text-[10px] font-bold tracking-widest uppercase">
                Email
              </label>
              <div className="relative">
                <Mail className="text-text-muted absolute top-1/2 left-4 h-4 w-4 -translate-y-1/2" />
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="iterum-input w-full pl-12"
                  placeholder="imperator@roma.com"
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-text-muted ml-4 text-[10px] font-bold tracking-widest uppercase">
                Contrase├▒a
              </label>
              <div className="relative">
                <Lock className="text-text-muted absolute top-1/2 left-4 h-4 w-4 -translate-y-1/2" />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="iterum-input w-full pl-12"
                  placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                />
              </div>
            </div>

            {error && (
              <motion.div
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                className="bg-accent/5 border-accent/20 flex items-start gap-3 rounded-[20px] border p-4 text-xs font-medium"
              >
                <Info className="text-accent mt-0.5 h-4 w-4 shrink-0" />
                <span className="text-text-primary leading-relaxed dark:text-[--dark-text-primary]">
                  {error}
                </span>
              </motion.div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="iterum-button-primary group w-full justify-center py-4 text-sm"
            >
              {loading ? (
                <Loader2 className="h-5 w-5 animate-spin" />
              ) : (
                <>
                  {isLogin ? 'Entrar' : 'Registrarse'}
                  <ArrowRight className="ml-2 h-4 w-4 transition-transform group-hover:translate-x-1" />
                </>
              )}
            </button>
          </form>

          <div className="relative my-10">
            <div className="absolute inset-0 flex items-center">
              <div className="border-border-subtle w-full border-t dark:border-[--dark-border-subtle]"></div>
            </div>
            <div className="relative flex justify-center text-[10px] font-bold tracking-widest uppercase">
              <span className="bg-bg-primary px-4 text-text-muted dark:bg-[--dark-bg-primary]">
                O continuar con
              </span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => handleSocialLogin('google')}
              className="bg-bg-secondary border-border-subtle hover:border-accent/40 flex items-center justify-center gap-3 rounded-[20px] border py-3 transition-all dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]"
            >
              <Chrome className="h-5 w-5" />
              <span className="text-[10px] font-bold tracking-widest uppercase">Google</span>
            </button>
            <button
              onClick={() => handleSocialLogin('github')}
              className="bg-bg-secondary border-border-subtle hover:border-accent/40 flex items-center justify-center gap-3 rounded-[20px] border py-3 transition-all dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]"
            >
              <Github className="h-5 w-5" />
              <span className="text-[10px] font-bold tracking-widest uppercase">GitHub</span>
            </button>
          </div>

          <div className="mt-10 text-center">
            <button
              onClick={() => setIsLogin(!isLogin)}
              className="text-text-muted hover:text-accent text-[10px] font-bold tracking-widest uppercase transition-colors"
            >
              {isLogin ? '┬┐No tienes cuenta? Registrate' : '┬┐Ya tienes cuenta? Entra'}
            </button>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

import { useState } from 'react';
import {
  format,
  addMonths,
  subMonths,
  startOfMonth,
  endOfMonth,
  startOfWeek,
  endOfWeek,
  isSameMonth,
  isSameDay,
  addDays,
  isToday,
} from 'date-fns';
import { es } from 'date-fns/locale';
import { ChevronLeft, ChevronRight, Plus } from 'lucide-react';
import { Task } from '../types';
import { cn } from '../utils';

interface CalendarViewProps {
  tasks: Task[];
  onDateSelect: (date: Date) => void;
  onToggle: (id: string) => void;
  onEdit: (task: Task) => void;
}

export function CalendarView({ tasks, onDateSelect, onToggle, onEdit }: CalendarViewProps) {
  const [currentDate, setCurrentDate] = useState(new Date());

  const nextMonth = () => setCurrentDate(addMonths(currentDate, 1));
  const prevMonth = () => setCurrentDate(subMonths(currentDate, 1));

  const monthStart = startOfMonth(currentDate);
  const monthEnd = endOfMonth(monthStart);
  const startDate = startOfWeek(monthStart, { weekStartsOn: 1 });
  const endDate = endOfWeek(monthEnd, { weekStartsOn: 1 });

  const dateFormat = 'MMMM yyyy';
  const days = [];
  let day = startDate;
  let formattedDate = '';

  while (day <= endDate) {
    for (let i = 0; i < 7; i++) {
      formattedDate = format(day, 'd');
      const cloneDay = day;
      const dayTasks = tasks.filter((task) => isSameDay(task.date, cloneDay));

      days.push(
        <div
          key={day.toString()}
          onClick={() => onDateSelect(cloneDay)}
          className={cn(
            'group relative min-h-[120px] cursor-pointer border-r border-b border-zinc-200 p-2 transition-colors hover:bg-zinc-50 dark:border-zinc-800 dark:hover:bg-zinc-800/50',
            !isSameMonth(day, monthStart)
              ? 'bg-zinc-50/50 text-zinc-400 dark:bg-zinc-900/50 dark:text-zinc-600'
              : 'bg-white text-zinc-900 dark:bg-zinc-900 dark:text-zinc-100',
            isToday(day) && 'bg-indigo-50/30 dark:bg-indigo-500/5',
          )}
        >
          <div className="flex items-start justify-between">
            <span
              className={cn(
                'flex h-7 w-7 items-center justify-center rounded-full text-sm font-medium',
                isToday(day) ? 'bg-indigo-600 text-white' : '',
              )}
            >
              {formattedDate}
            </span>
            <button className="p-1 text-zinc-400 opacity-0 transition-opacity group-hover:opacity-100 hover:text-indigo-600 dark:text-zinc-500 dark:hover:text-indigo-400">
              <Plus className="h-4 w-4" />
            </button>
          </div>

          <div className="scrollbar-hide mt-2 max-h-[80px] space-y-1 overflow-y-auto">
            {dayTasks.slice(0, 3).map((task) => (
              <div
                key={task.id}
                onClick={(e) => {
                  e.stopPropagation();
                  onEdit(task);
                }}
                className={cn(
                  'truncate rounded-md px-1.5 py-1 text-xs transition-all',
                  task.completed
                    ? 'bg-zinc-100 text-zinc-400 line-through dark:bg-zinc-800 dark:text-zinc-500'
                    : 'bg-zinc-100 text-zinc-700 hover:bg-zinc-200 dark:bg-zinc-800 dark:text-zinc-300 dark:hover:bg-zinc-700',
                )}
                style={
                  !task.completed && task.color ? { borderLeft: `3px solid ${task.color}` } : {}
                }
              >
                {format(task.date, 'HH:mm')} {task.title}
              </div>
            ))}
            {dayTasks.length > 3 && (
              <div className="px-1 text-xs font-medium text-zinc-500 dark:text-zinc-400">
                +{dayTasks.length - 3} m├ís
              </div>
            )}
          </div>
        </div>,
      );
      day = addDays(day, 1);
    }
  }

  const weekDays = ['Lun', 'Mar', 'Mi├®', 'Jue', 'Vie', 'S├íb', 'Dom'];

  return (
    <div className="iterum-card shadow-accent/5 overflow-hidden border-none p-0 shadow-xl">
      <div className="border-border-subtle flex items-center justify-between border-b px-8 py-6 dark:border-[--dark-border-subtle]">
        <h2 className="text-text-primary text-2xl font-bold capitalize dark:text-[--dark-text-primary]">
          {format(currentDate, dateFormat, { locale: es })}
        </h2>
        <div className="flex items-center gap-3">
          <button
            onClick={prevMonth}
            className="hover:bg-bg-primary text-text-muted rounded-[12px] p-2.5 transition-colors dark:hover:bg-[--dark-bg-primary]"
          >
            <ChevronLeft className="h-5 w-5" />
          </button>
          <button
            onClick={() => setCurrentDate(new Date())}
            className="text-accent hover:bg-accent/10 rounded-[12px] px-4 py-2 text-sm font-bold transition-colors"
          >
            Hoy
          </button>
          <button
            onClick={nextMonth}
            className="hover:bg-bg-primary text-text-muted rounded-[12px] p-2.5 transition-colors dark:hover:bg-[--dark-bg-primary]"
          >
            <ChevronRight className="h-5 w-5" />
          </button>
        </div>
      </div>

      <div className="bg-bg-primary/30 grid grid-cols-7 dark:bg-[--dark-bg-primary]/30">
        {weekDays.map((day) => (
          <div
            key={day}
            className="text-text-muted py-4 text-center text-[10px] font-bold tracking-[0.2em] uppercase"
          >
            {day}
          </div>
        ))}
      </div>
      <div className="grid grid-cols-7">{days}</div>
    </div>
  );
}

import { useState, useEffect, FormEvent } from 'react';
import { X, Zap, Repeat, Target, Clock, BookOpen, Sparkles } from 'lucide-react';
import { Habit, HabitType } from '../types';
import { cn } from '../utils';
import { GoogleGenAI } from '@google/genai';
import { useObjectiveStore } from '../store/useObjectiveStore';
import { useUserStore } from '../store/useUserStore';

interface HabitModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (habit: Omit<Habit, 'id' | 'isActive' | 'createdAt'>) => void;
  habitToEdit?: Habit;
}

const COLORS = [
  '#C9935A', // Amber (Iterum)
  '#A0522D', // Terracotta (Iterum)
  '#ef4444', // red
  '#22c55e', // green
  '#3b82f6', // blue
  '#a855f7', // purple
  '#64748b', // slate
];

const HABIT_TYPES: { type: HabitType; label: string; icon: any }[] = [
  { type: 'yesno', label: 'S├¡/No', icon: Zap },
  { type: 'numeric', label: 'Num├®rico', icon: Target },
  { type: 'timer', label: 'Timer', icon: Clock },
];

const FREQUENCIES = [
  { value: 'daily', label: 'Cada d├¡a' },
  { value: 'weekly:Mon,Wed,Fri', label: 'Lun, Mi├®, Vie' },
  { value: 'weekly:Sat,Sun', label: 'Fines de semana' },
  { value: 'everyXdays:2', label: 'Cada 2 d├¡as' },
];

export function HabitModal({ isOpen, onClose, onSave, habitToEdit }: HabitModalProps) {
  const objectives = useObjectiveStore((state) => state.objectives);
  const userLevel = useUserStore((state) => state.stats.level);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [frequency, setFrequency] = useState('daily');
  const [type, setType] = useState<HabitType>('yesno');
  const [targetValue, setTargetValue] = useState<number>(1);
  const [unit, setUnit] = useState('');
  const [category, setCategory] = useState('');
  const [color, setColor] = useState(COLORS[0]);
  const [reminderTime, setReminderTime] = useState('');
  const [selectedObjectiveIds, setSelectedObjectiveIds] = useState<string[]>([]);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const suggestWithAI = async () => {
    if (!name.trim() || !navigator.onLine) return;
    setIsSuggesting(true);
    try {
      const apiKey = process.env.GEMINI_API_KEY;
      if (!apiKey) {
        setIsSuggesting(false);
        return;
      }
      const ai = new GoogleGenAI({ apiKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Sugiere configuraci├│n para un h├íbito llamado "${name}". 
        Responde SOLO en JSON con este formato: 
        { "frequency": "daily" | "weekly:Mon,Wed,Fri" | "everyXdays:2", "category": "string", "description": "string", "type": "yesno" | "numeric" | "timer", "unit": "string", "targetValue": number }`,
        config: { responseMimeType: 'application/json' },
      });

      const suggestion = JSON.parse(response.text || '{}');
      if (suggestion.frequency) setFrequency(suggestion.frequency);
      if (suggestion.category) setCategory(suggestion.category);
      if (suggestion.description) setDescription(suggestion.description);
      if (suggestion.type) setType(suggestion.type);
      if (suggestion.unit) setUnit(suggestion.unit);
      if (suggestion.targetValue) setTargetValue(suggestion.targetValue);
    } catch (error: any) {
      // Fallback for network/adblocker errors
      const errorStr = String(error?.message || error);
      if (errorStr.includes('xhr error') || errorStr.includes('fetch')) {
        console.warn('AI Suggestion network error (fallback applied):', errorStr);
        setFrequency('daily');
        setType('yesno');
        setDescription('Un buen h├íbito para empezar.');
      } else {
        console.error('AI Suggestion failed', error);
      }
    } finally {
      setIsSuggesting(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      if (habitToEdit) {
        setName(habitToEdit.name);
        setDescription(habitToEdit.description || '');
        setFrequency(habitToEdit.frequency);
        setType(habitToEdit.type);
        setTargetValue(habitToEdit.targetValue || 1);
        setUnit(habitToEdit.unit || '');
        setCategory(habitToEdit.category || '');
        setColor(habitToEdit.color || COLORS[0]);
        setReminderTime(habitToEdit.reminderTime || '');
        setSelectedObjectiveIds(habitToEdit.objectiveIds || []);
      } else {
        setName('');
        setDescription('');
        setFrequency('daily');
        setType('yesno');
        setTargetValue(1);
        setUnit('');
        setCategory('');
        setColor(COLORS[0]);
        setReminderTime('');
        setSelectedObjectiveIds([]);
      }
    }
  }, [isOpen, habitToEdit]);

  if (!isOpen) return null;

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    onSave({
      name: name.trim(),
      description: description.trim(),
      frequency,
      type,
      targetValue: type !== 'yesno' ? targetValue : undefined,
      unit: type !== 'yesno' ? unit : undefined,
      category: category.trim(),
      color,
      reminderTime: reminderTime || undefined,
      objectiveIds: selectedObjectiveIds.length > 0 ? selectedObjectiveIds : undefined,
    });
    onClose();
  };

  const toggleObjective = (id: string) => {
    setSelectedObjectiveIds((prev) =>
      prev.includes(id) ? prev.filter((oid) => oid !== id) : [...prev, id],
    );
  };

  return (
    <div className="bg-bg-primary/40 fixed inset-0 z-50 flex items-center justify-center p-4 backdrop-blur-md dark:bg-black/60">
      <div
        className="bg-bg-primary animate-in fade-in zoom-in-95 border-border-subtle w-full max-w-md overflow-hidden rounded-[24px] border shadow-2xl duration-300 dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-primary]"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="border-border-subtle flex items-center justify-between border-b px-8 py-6 dark:border-[--dark-border-subtle]">
          <h2 className="text-xl font-bold">{habitToEdit ? 'Editar H├íbito' : 'Nuevo H├íbito'}</h2>
          <button
            onClick={onClose}
            className="text-text-muted hover:text-accent bg-bg-secondary rounded-[12px] p-2 transition-colors dark:bg-[--dark-bg-secondary]"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="max-h-[70vh] space-y-6 overflow-y-auto p-8">
          <div>
            <div className="mb-2 flex items-center justify-between">
              <label
                htmlFor="name"
                className="text-text-muted block text-xs font-bold tracking-widest uppercase"
              >
                Nombre del H├íbito
              </label>
              {name.trim() && !habitToEdit && navigator.onLine && (
                <button
                  type="button"
                  onClick={suggestWithAI}
                  disabled={isSuggesting}
                  className={cn(
                    'flex items-center gap-1.5 text-[10px] font-bold tracking-widest uppercase transition-all',
                    isSuggesting ? 'text-accent animate-pulse' : 'text-accent/60 hover:text-accent',
                  )}
                >
                  <Sparkles className="h-3 w-3" />
                  {isSuggesting ? 'Sugiriendo...' : 'Sugerir con IA'}
                </button>
              )}
            </div>
            <input
              id="name"
              type="text"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="iterum-input w-full text-lg font-semibold"
              placeholder="Ej. Meditar, Leer, Correr..."
              autoFocus
            />
          </div>

          <div className="grid grid-cols-3 gap-2">
            {HABIT_TYPES.map((item) => (
              <button
                key={item.type}
                type="button"
                onClick={() => setType(item.type)}
                className={cn(
                  'flex flex-col items-center gap-2 rounded-[16px] border p-3 transition-all',
                  type === item.type
                    ? 'bg-accent/10 border-accent text-accent shadow-sm'
                    : 'bg-bg-secondary border-border-subtle text-text-muted opacity-60 hover:opacity-100 dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]',
                )}
              >
                <item.icon className="h-5 w-5" />
                <span className="text-[10px] font-bold tracking-wider uppercase">{item.label}</span>
              </button>
            ))}
          </div>

          {type !== 'yesno' && (
            <div className="animate-in fade-in slide-in-from-top-2 grid grid-cols-2 gap-4">
              <div>
                <label
                  htmlFor="target"
                  className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
                >
                  Objetivo
                </label>
                <input
                  id="target"
                  type="number"
                  required
                  value={targetValue}
                  onChange={(e) => setTargetValue(Number(e.target.value))}
                  className="iterum-input w-full"
                />
              </div>
              <div>
                <label
                  htmlFor="unit"
                  className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
                >
                  Unidad
                </label>
                <input
                  id="unit"
                  type="text"
                  required
                  value={unit}
                  onChange={(e) => setUnit(e.target.value)}
                  className="iterum-input w-full"
                  placeholder="Ej. min, km, p├íg"
                />
              </div>
            </div>
          )}

          <div>
            <label
              htmlFor="frequency"
              className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
            >
              Frecuencia
            </label>
            <select
              id="frequency"
              value={frequency}
              onChange={(e) => setFrequency(e.target.value)}
              className="iterum-input w-full appearance-none"
            >
              {FREQUENCIES.map((f) => (
                <option key={f.value} value={f.value}>
                  {f.label}
                </option>
              ))}
            </select>
          </div>

          {objectives.length > 0 && (
            <div>
              <label className="text-text-muted mb-3 block text-xs font-bold tracking-widest uppercase">
                Contribuye a Objetivos
              </label>
              <div className="flex flex-wrap gap-2">
                {objectives.map((obj) => (
                  <button
                    key={obj.id}
                    type="button"
                    onClick={() => toggleObjective(obj.id)}
                    className={cn(
                      'rounded-full border px-3 py-1.5 text-[10px] font-bold tracking-wider uppercase transition-all',
                      selectedObjectiveIds.includes(obj.id)
                        ? 'bg-accent/10 border-accent text-accent'
                        : 'bg-bg-secondary border-border-subtle text-text-muted',
                    )}
                  >
                    {obj.title}
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label
                htmlFor="category"
                className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
              >
                Categor├¡a
              </label>
              <input
                id="category"
                type="text"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                className="iterum-input w-full"
                placeholder="Salud, Foco..."
              />
            </div>
            <div>
              <label
                htmlFor="reminder"
                className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
              >
                Recordatorio
              </label>
              <input
                id="reminder"
                type="time"
                value={reminderTime}
                onChange={(e) => setReminderTime(e.target.value)}
                className="iterum-input w-full [color-scheme:light] dark:[color-scheme:dark]"
              />
            </div>
          </div>

          <div>
            <div className="mb-3 flex items-center justify-between">
              <label className="text-text-muted block text-xs font-bold tracking-widest uppercase">
                Color Distintivo
              </label>
              {userLevel < 2 && (
                <span className="text-accent flex items-center gap-1 text-[10px] font-bold tracking-widest uppercase">
                  <Zap className="h-3 w-3" />
                  Nivel 2 Desbloquea m├ís
                </span>
              )}
            </div>
            <div className="flex items-center gap-3">
              {COLORS.map((c, idx) => {
                const isLocked = userLevel < 2 && idx > 1;
                return (
                  <button
                    key={c}
                    type="button"
                    disabled={isLocked}
                    onClick={() => setColor(c)}
                    className={cn(
                      'relative h-7 w-7 rounded-full border-2 transition-all',
                      color === c
                        ? 'border-text-primary scale-125 shadow-lg'
                        : 'border-transparent hover:scale-110',
                      isLocked && 'cursor-not-allowed opacity-20 grayscale',
                    )}
                    style={{ backgroundColor: c }}
                  >
                    {isLocked && (
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Zap className="text-text-primary h-3 w-3" />
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          <div className="flex justify-end gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="text-text-muted hover:text-text-primary px-6 py-3 text-sm font-bold transition-colors"
            >
              Cancelar
            </button>
            <button type="submit" className="iterum-button-primary">
              {habitToEdit ? 'Guardar Cambios' : 'Crear H├íbito'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

