                    {task.migrated && (
                      <span className="bg-accent-secondary/10 text-accent-secondary border-accent-secondary/20 rounded-full border px-2 py-0.5 text-[10px] font-bold tracking-wider uppercase">
                        retrasado
                      </span>
                    )}
                  </div>

                  {task.description && (
                    <p
                      className={cn(
                        'text-text-muted line-clamp-1 text-sm',
                        task.completed && 'line-through',
                      )}
                    >
                      {task.description}
                    </p>
                  )}
                </div>

                <div className="flex items-center gap-4 opacity-0 transition-opacity group-hover:opacity-100">
                  <div className="text-text-muted flex items-center gap-1 text-xs font-medium">
                    <Clock className="h-3.5 w-3.5" />
                    {format(task.date, 'HH:mm')}
                  </div>
                  <div className="bg-border-subtle h-4 w-[1px]" />
                  <button
                    onClick={() => onEdit(task)}
                    className="text-text-muted hover:text-accent p-1.5 transition-colors"
                  >
                    <Edit2 className="h-4 w-4" />
                  </button>
                  <button
                    onClick={() => onDelete(task.id)}
                    className="text-text-muted hover:text-accent-secondary p-1.5 transition-colors"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

import React from 'react';
import { Target, Calendar, ChevronRight, Edit2, CheckCircle2, Circle } from 'lucide-react';
import { Objective, Milestone } from '../types';
import { cn } from '../utils';
import { motion } from 'motion/react';

interface ObjectiveCardProps {
  objective: Objective;
  onEdit: (objective: Objective) => void;
  onToggleMilestone?: (objectiveId: string, milestoneId: string) => void;
}

export const ObjectiveCard: React.FC<ObjectiveCardProps> = ({
  objective,
  onEdit,
  onToggleMilestone,
}) => {
  const progress = Math.min(
    100,
    Math.round((objective.currentValue / objective.targetValue) * 100),
  );
  const completedMilestones = objective.milestones?.filter((m) => m.completed).length || 0;
  const totalMilestones = objective.milestones?.length || 0;

  return (
    <motion.div
      layout
      className="iterum-card group relative flex flex-col gap-6 overflow-hidden p-6"
    >
      <div className="flex items-start justify-between">
        <div className="space-y-1">
          <div className="flex items-center gap-2">
            <h3 className="text-xl font-bold tracking-tight">{objective.title}</h3>
          </div>
          {objective.description && (
            <p className="text-text-muted line-clamp-2 text-sm">{objective.description}</p>
          )}
        </div>

        <button
          onClick={() => onEdit(objective)}
          className="text-text-muted hover:text-accent p-2 opacity-0 transition-all group-hover:opacity-100"
        >
          <Edit2 className="h-4 w-4" />
        </button>
      </div>

      <div className="space-y-3">
        <div className="flex items-end justify-between">
          <div className="flex flex-col">
            <span className="text-text-muted text-[10px] font-bold tracking-widest uppercase">
              Progreso
            </span>
            <span className="text-accent text-2xl font-bold">
              {objective.currentValue}{' '}
              <span className="text-text-muted text-sm font-medium">
                / {objective.targetValue} {objective.unit}
              </span>
            </span>
          </div>
          <div className="text-right">
            <span className="text-lg font-bold">{progress}%</span>
          </div>
        </div>

        <div className="bg-bg-secondary border-border-subtle h-3 overflow-hidden rounded-full border dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]">
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 1, ease: 'easeOut' }}
            className="bg-accent h-full rounded-full shadow-[0_0_12px_rgba(201,147,90,0.3)]"
            style={{ backgroundColor: objective.color }}
          />
        </div>
      </div>

      {objective.milestones && objective.milestones.length > 0 && (
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <span className="text-text-muted text-[10px] font-bold tracking-widest uppercase">
              Hitos ({completedMilestones}/{totalMilestones})
            </span>
          </div>
          <div className="space-y-2">
            {objective.milestones.map((milestone) => (
              <button
                key={milestone.id}
                onClick={() => onToggleMilestone?.(objective.id, milestone.id)}
                className={cn(
                  'flex w-full items-center gap-3 rounded-[12px] border p-2.5 text-left transition-all',
                  milestone.completed
                    ? 'bg-accent/5 border-accent/20 text-text-primary'
                    : 'bg-bg-secondary/50 border-border-subtle text-text-muted hover:border-accent/30',
                )}
              >
                {milestone.completed ? (
                  <CheckCircle2 className="text-accent h-4 w-4 shrink-0" />
                ) : (
                  <Circle className="text-text-muted/30 h-4 w-4 shrink-0" />
                )}
                <span
                  className={cn(
                    'text-xs font-medium',
                    milestone.completed && 'line-through opacity-60',
                  )}
                >
                  {milestone.title}
                </span>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="border-border-subtle flex items-center justify-between border-t pt-2 dark:border-[--dark-border-subtle]">
        <div className="flex items-center gap-4">
          {objective.deadline && (
            <div className="text-text-muted flex items-center gap-1.5 text-[10px] font-bold tracking-wider uppercase">
              <Calendar className="h-3.5 w-3.5" />
              {new Date(objective.deadline).toLocaleDateString()}
            </div>
          )}
        </div>

        <div className="text-accent flex items-center gap-1 text-[10px] font-bold tracking-wider uppercase">
          Detalles
          <ChevronRight className="h-3 w-3" />
        </div>
      </div>
    </motion.div>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import {
  Sparkles,
  Target,
  Repeat,
  Zap,
  ChevronRight,
  ChevronLeft,
  CheckCircle2,
  Trophy,
  ArrowRight,
} from 'lucide-react';
import { cn } from '../utils';

type Step = {
  id: number;
  title: string;
  description: string;
  icon: any;
  color: string;
};

const STEPS: Step[] = [
  {
    id: 0,
    title: 'Bienvenido a Iterum',
    description:
      'Iterum es tu compa├▒ero para cerrar ciclos diarios de forma consciente y construir una vida con prop├│sito.',
    icon: Sparkles,
    color: 'text-accent',
  },
  {
    id: 1,
    title: 'H├íbitos con Intenci├│n',
    description:
      'No solo taches tareas. Registra tus h├íbitos, a├▒ade reflexiones y mira c├│mo tus rachas crecen d├¡a a d├¡a.',
    icon: Repeat,
    color: 'text-accent-secondary',
  },
  {
    id: 2,
    title: 'Objetivos Claros',
    description:
      'Vincula tus h├íbitos diarios a metas a largo plazo. Cada peque├▒a acci├│n te acerca a tu gran objetivo.',
    icon: Target,
    color: 'text-green-500',
  },
  {
    id: 3,
    title: 'Gamificaci├│n Real',
    description:
      'Gana EXP por tu disciplina y consistencia. Desbloquea nuevas funciones a medida que subes de nivel.',
    icon: Trophy,
    color: 'text-yellow-500',
  },
];

interface OnboardingWizardProps {
  onComplete: () => void;
}

export function OnboardingWizard({ onComplete }: OnboardingWizardProps) {
  const [currentStep, setCurrentStep] = useState(0);

  const handleNext = () => {
    if (currentStep < STEPS.length - 1) {
      setCurrentStep((prev) => prev + 1);
    } else {
      onComplete();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  const step = STEPS[currentStep];
  const Icon = step.icon;

  return (
    <div className="bg-bg-primary/90 fixed inset-0 z-[100] flex items-center justify-center p-6 backdrop-blur-md dark:bg-[--dark-bg-primary]/90">
      <motion.div
        initial={{ opacity: 0, scale: 0.9, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        className="bg-bg-secondary border-border-subtle w-full max-w-lg overflow-hidden rounded-[32px] border shadow-2xl dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]"
      >
        <div className="p-10">
          <div className="mb-12 flex items-center justify-between">
            <div className="flex gap-1.5">
              {STEPS.map((_, idx) => (
                <div
                  key={idx}
                  className={cn(
                    'h-1.5 rounded-full transition-all duration-500',
                    idx === currentStep
                      ? 'bg-accent w-8'
                      : 'bg-border-subtle w-2 dark:bg-[--dark-border-subtle]',
                  )}
                />
              ))}
            </div>
            <span className="text-text-muted text-[10px] font-bold tracking-widest uppercase">
              Paso {currentStep + 1} de {STEPS.length}
            </span>
          </div>

          <AnimatePresence mode="wait">
            <motion.div
              key={currentStep}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              transition={{ duration: 0.3 }}
              className="text-center"
            >
              <div
                className={cn(
                  'bg-bg-primary mx-auto mb-8 flex h-20 w-20 items-center justify-center rounded-[24px] shadow-inner dark:bg-[--dark-bg-primary]',
                  step.color,
                )}
              >
                <Icon className="h-10 w-10" />
              </div>
              <h2 className="mb-4 text-3xl font-bold tracking-tight">{step.title}</h2>
              <p className="text-text-muted mb-12 leading-relaxed dark:text-[--dark-text-muted]">
                {step.description}
              </p>
            </motion.div>
          </AnimatePresence>

          <div className="flex items-center justify-between gap-4">
            <button
              onClick={handleBack}
              disabled={currentStep === 0}
              className={cn(
                'flex items-center gap-2 rounded-full px-6 py-3 text-sm font-bold transition-all',
                currentStep === 0
                  ? 'pointer-events-none opacity-0'
                  : 'text-text-muted hover:text-text-primary dark:hover:text-[--dark-text-primary]',
              )}
            >
              <ChevronLeft className="h-4 w-4" />
              Atr├ís
            </button>

            <button
              onClick={handleNext}
              className="bg-accent text-bg-primary shadow-accent/20 flex items-center gap-2 rounded-full px-8 py-3 text-sm font-bold shadow-lg transition-all hover:scale-105 active:scale-95"
            >
              {currentStep === STEPS.length - 1 ? 'Empezar ahora' : 'Siguiente'}
              {currentStep === STEPS.length - 1 ? (
                <CheckCircle2 className="h-4 w-4" />
              ) : (
                <ChevronRight className="h-4 w-4" />
              )}
            </button>
          </div>
        </div>

        {currentStep === 3 && (
          <div className="bg-accent/5 border-border-subtle border-t p-6 text-center dark:border-[--dark-border-subtle]">
            <p className="text-accent flex items-center justify-center gap-2 text-xs font-medium">
              <Zap className="h-3 w-3" />
              ┬íNivel 2 desbloquea colores personalizados para tus h├íbitos!
            </p>
          </div>
        )}
      </motion.div>
    </div>
  );
}

import React, { useState, useEffect, FormEvent } from 'react';
import { X, Zap, Target, BookOpen, Repeat } from 'lucide-react';
import { format } from 'date-fns';
import { Task, EntityType } from '../types';
import { cn } from '../utils';

interface TaskModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Omit<Task, 'id' | 'completed'>) => void;
  initialDate?: Date;
  taskToEdit?: Task;
}

const COLORS = [
  '#C9935A', // Amber (Iterum)
  '#A0522D', // Terracotta (Iterum)
  '#ef4444', // red
  '#22c55e', // green
  '#3b82f6', // blue
  '#a855f7', // purple
  '#64748b', // slate
];

const ENTITY_TYPES: { type: EntityType; label: string; icon: any }[] = [
  { type: 'task', label: 'Tarea', icon: Zap },
  { type: 'habit', label: 'H├íbito', icon: Repeat },
  { type: 'objective', label: 'Objetivo', icon: Target },
  { type: 'journal', label: 'Nota', icon: BookOpen },
];

const FREQUENCIES = [
  { value: 'daily', label: 'Cada d├¡a' },
  { value: 'weekly:Mon,Wed,Fri', label: 'Lun, Mi├®, Vie' },
  { value: 'weekly:Sat,Sun', label: 'Fines de semana' },
];

export function TaskModal({
  isOpen,
  onClose,
  onSave,
  initialDate = new Date(),
  taskToEdit,
}: TaskModalProps) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [dateStr, setDateStr] = useState('');
  const [timeStr, setTimeStr] = useState('');
  const [color, setColor] = useState(COLORS[0]);
  const [type, setType] = useState<EntityType>('task');

  // Habit specific
  const [habitFrequency, setHabitFrequency] = useState('daily');
  const [habitType, setHabitType] = useState<'yesno' | 'numeric'>('yesno');
  const [habitTarget, setHabitTarget] = useState(1);
  const [habitUnit, setHabitUnit] = useState('');

  // Objective specific
  const [objTarget, setObjTarget] = useState(100);
  const [objUnit, setObjUnit] = useState('%');
  const [objDeadline, setObjDeadline] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (taskToEdit) {
        setTitle(taskToEdit.title);
        setDescription(taskToEdit.description || '');
        setDateStr(format(taskToEdit.date, 'yyyy-MM-dd'));
        setTimeStr(format(taskToEdit.date, 'HH:mm'));
        setColor(taskToEdit.color || COLORS[0]);
        setType(taskToEdit.type || 'task');
      } else {
        setDateStr(format(initialDate, 'yyyy-MM-dd'));
        setTimeStr(format(initialDate, 'HH:mm'));
        setTitle('');
        setDescription('');
        setColor(COLORS[0]);
        setType('task');
        setHabitFrequency('daily');
        setHabitType('yesno');
        setHabitTarget(1);
        setHabitUnit('');
        setObjTarget(100);
        setObjUnit('%');
        setObjDeadline('');
      }
    }
  }, [isOpen, initialDate, taskToEdit]);

  if (!isOpen) return null;

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    const combinedDate = dateStr && timeStr ? new Date(`${dateStr}T${timeStr}`) : new Date();

    onSave({
      title: title.trim(),
      description: description.trim(),
      date: combinedDate,
      color,
      type,
      // Pass extra data for App.tsx to handle
      ...(type === 'habit' && {
        habitData: {
          frequency: habitFrequency,
          type: habitType,
          targetValue: habitTarget,
          unit: habitUnit,
        },
      }),
      ...(type === 'objective' && {
        objectiveData: {
          targetValue: objTarget,
          unit: objUnit,
          deadline: objDeadline ? new Date(objDeadline) : undefined,
        },
      }),
    } as any);
    onClose();
  };

  return (
    <div className="bg-bg-primary/40 fixed inset-0 z-50 flex items-center justify-center p-4 backdrop-blur-md dark:bg-black/60">
      <div
        className="bg-bg-primary animate-in fade-in zoom-in-95 border-border-subtle w-full max-w-md overflow-hidden rounded-[24px] border shadow-2xl duration-300 dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-primary]"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="border-border-subtle flex items-center justify-between border-b px-8 py-6 dark:border-[--dark-border-subtle]">
          <h2 className="flex items-center gap-3 text-xl font-bold">
            <div className="bg-accent/10 flex h-10 w-10 items-center justify-center rounded-[14px]">
              {ENTITY_TYPES.find((t) => t.type === type)?.icon &&
                React.createElement(ENTITY_TYPES.find((t) => t.type === type)!.icon, {
                  className: 'w-5 h-5 text-accent',
                })}
            </div>
            {taskToEdit ? 'Editar' : 'Capturar'} {ENTITY_TYPES.find((t) => t.type === type)?.label}
          </h2>
          <button
            onClick={onClose}
            className="text-text-muted hover:text-accent bg-bg-secondary rounded-[12px] p-2 transition-colors dark:bg-[--dark-bg-secondary]"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        <form
          onSubmit={handleSubmit}
          className="iterum-scrollbar max-h-[75vh] space-y-6 overflow-y-auto p-8"
        >
          {/* Entity Type Selector */}
          <div className="grid grid-cols-4 gap-2">
            {ENTITY_TYPES.map((item) => (
              <button
                key={item.type}
                type="button"
                onClick={() => setType(item.type)}
                className={cn(
                  'flex flex-col items-center gap-2 rounded-[16px] border p-3 transition-all',
                  type === item.type
                    ? 'bg-accent/10 border-accent text-accent shadow-sm'
                    : 'bg-bg-secondary border-border-subtle text-text-muted opacity-60 hover:opacity-100 dark:border-[--dark-border-subtle] dark:bg-[--dark-bg-secondary]',
                )}
              >
                <item.icon className="h-5 w-5" />
                <span className="text-[10px] font-bold tracking-wider uppercase">{item.label}</span>
              </button>
            ))}
          </div>

          <div>
            <label
              htmlFor="title"
              className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase"
            >
              {type === 'habit'
                ? 'Nombre del H├íbito'
                : type === 'objective'
                  ? 'T├¡tulo del Objetivo'
                  : type === 'journal'
                    ? 'T├¡tulo de la Nota'
                    : 'T├¡tulo'}
            </label>
            <input
              id="title"
              type="text"
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="iterum-input w-full text-lg font-semibold"
              placeholder={
                type === 'habit'
                  ? 'Ej. Meditar, Correr...'
                  : type === 'objective'
                    ? 'Ej. Marat├│n 2026'
                    : '┬┐Qu├® tienes en mente?'
              }
              autoFocus
            />
          </div>

          {type === 'habit' && (
            <div className="animate-in fade-in slide-in-from-top-2 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase">
                    Tipo
                  </label>
                  <div className="flex gap-2">
                    <button
                      type="button"
                      onClick={() => setHabitType('yesno')}
                      className={cn(
                        'flex-1 rounded-xl border px-3 py-2 text-[10px] font-bold tracking-widest uppercase transition-all',
                        habitType === 'yesno'
                          ? 'bg-accent text-bg-primary border-accent'
                          : 'bg-bg-secondary border-border-subtle text-text-muted',
                      )}
                    >
                      S├¡/No
                    </button>
                    <button
                      type="button"
                      onClick={() => setHabitType('numeric')}
                      className={cn(
                        'flex-1 rounded-xl border px-3 py-2 text-[10px] font-bold tracking-widest uppercase transition-all',
                        habitType === 'numeric'
                          ? 'bg-accent text-bg-primary border-accent'
                          : 'bg-bg-secondary border-border-subtle text-text-muted',
                      )}
                    >
                      N├║mero
                    </button>
                  </div>
                </div>
                <div>
                  <label className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase">
                    Frecuencia
                  </label>
                  <select
                    value={habitFrequency}
                    onChange={(e) => setHabitFrequency(e.target.value)}
                    className="iterum-input w-full text-xs"
                  >
                    {FREQUENCIES.map((f) => (
                      <option key={f.value} value={f.value}>
                        {f.label}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              {habitType === 'numeric' && (
                <div className="animate-in fade-in slide-in-from-top-2 grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase">
                      Meta
                    </label>
                    <input
                      type="number"
                      value={habitTarget}
                      onChange={(e) => setHabitTarget(Number(e.target.value))}
                      className="iterum-input w-full"
                    />
                  </div>
                  <div>
                    <label className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase">
                      Unidad
                    </label>
                    <input
                      type="text"
                      value={habitUnit}
                      onChange={(e) => setHabitUnit(e.target.value)}
                      className="iterum-input w-full"
                      placeholder="km, p├íg..."
                    />
                  </div>
                </div>
              )}
            </div>
          )}

          {type === 'objective' && (
            <div className="animate-in fade-in slide-in-from-top-2 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-text-muted mb-2 block text-xs font-bold tracking-widest uppercase">
                    Meta
                  </label>
