import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('iterum_theme');
    if (saved === 'light' || saved === 'dark') return saved;
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  useEffect(() => {
    localStorage.setItem('iterum_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
  };

  return <ThemeContext.Provider value={{ theme, toggleTheme }}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

import { useUserStore } from '../store/useUserStore';
import { DayClosure, Task, Habit, HabitLog, WeeklyInsight } from '../types';
import { format, addDays } from 'date-fns';

export function useDayClosure() {
  const {
    closedDays,
    setClosedDays,
    addClosedDay,
    weeklyInsights,
    setWeeklyInsights,
    addWeeklyInsight: addWeeklyInsightToStore,
  } = useUserStore();

  const isDayClosed = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return closedDays.some((d) => d.date === dateStr);
  };

  const calculateStreak = () => {
    let streak = 0;
    let current = new Date();

    // Check if today is closed or yesterday was closed to continue streak
    if (!isDayClosed(current)) {
      current = addDays(current, -1);
    }

    while (isDayClosed(current)) {
      streak++;
      current = addDays(current, -1);
    }
    return streak;
  };

  const closeDay = async (
    date: Date,
    habits: Habit[],
    logs: HabitLog[],
    tasks: Task[],
    updateTask: (id: string, updates: Partial<Task>) => void,
    addTask: (task: Omit<Task, 'id' | 'completed'>) => void,
  ) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    if (isDayClosed(date)) return null;

    const summary = 'D├¡a cerrado con ├®xito.';

    // 1. Migrate uncompleted tasks
    const todayTasks = tasks.filter(
      (t) => format(t.date, 'yyyy-MM-dd') === dateStr && !t.completed,
    );
    todayTasks.forEach((t) => {
      updateTask(t.id, {
        date: addDays(t.date, 1),
        migrated: true,
      });
    });

    // 2. Handle uncompleted habits
    // (Optional logic for habits can be added here in the future)

    // 3. Mark day as closed
    const newClosure: DayClosure = {
      date: dateStr,
      summary,
      closedAt: new Date(),
    };

    setClosedDays([...closedDays, newClosure]);
    return newClosure;
  };

  const addWeeklyInsight = (insight: WeeklyInsight) => {
    const newInsight = { ...insight, generatedAt: new Date() };
    addWeeklyInsightToStore(newInsight);
  };

  return {
    closedDays,
    isDayClosed,
    closeDay,
    calculateStreak,
    setClosedDays,
    weeklyInsights,
    addWeeklyInsight,
    setWeeklyInsights,
  };
}

import { useState, useEffect } from 'react';
import { useTaskStore } from '../store/useTaskStore';
import { useHabitStore } from '../store/useHabitStore';
import { useObjectiveStore } from '../store/useObjectiveStore';
import { useUserStore } from '../store/useUserStore';
import { SyncService } from '../services/supabase';
import { useUIStore } from '../store/useUIStore';

export function useSync() {
  const [isSyncing, setIsSyncing] = useState(false);
  const [isRestoring, setIsRestoring] = useState(false);
  const { setToast } = useUIStore();
  const { userId } = useUserStore();

  const tasks = useTaskStore((state) => state.tasks);
  const habits = useHabitStore((state) => state.habits);
  const logs = useHabitStore((state) => state.logs);
  const objectives = useObjectiveStore((state) => state.objectives);
  const closedDays = useUserStore((state) => state.closedDays);
  const weeklyInsights = useUserStore((state) => state.weeklyInsights);
  const stats = useUserStore((state) => state.stats);

  const { setTasks } = useTaskStore();
  const { setHabits, setLogs } = useHabitStore();
  const { setObjectives } = useObjectiveStore();
  const { setClosedDays, setWeeklyInsights, setStats } = useUserStore();

  const handleSync = async () => {
    if (!import.meta.env.VITE_SUPABASE_URL) {
      setToast({
        isOpen: true,
        title: 'Configuraci├│n Requerida',
        message: 'Configura las variables de Supabase en .env para activar el Sync.',
      });
      return;
    }

    setIsSyncing(true);
    try {
      const allData = {
        tasks,
        habits,
        logs,
        objectives,
        closedDays,
        weeklyInsights,
        stats,
      };

      await SyncService.syncData(userId, allData);

      setToast({
        isOpen: true,
        title: 'Sincronizaci├│n Exitosa',
        message: 'Tus datos est├ín seguros en la nube.',
      });
    } catch (error) {
      console.error('Sync failed', error);
      setToast({
        isOpen: true,
        title: 'Error de Sincronizaci├│n',
        message: 'No se pudo conectar con el servidor.',
      });
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRestore = async () => {
    if (!import.meta.env.VITE_SUPABASE_URL) {
      setToast({
        isOpen: true,
        title: 'Configuraci├│n Requerida',
        message: 'Configura las variables de Supabase en .env para activar el Restore.',
      });
      return;
    }

    if (
      !window.confirm('┬┐Est├ís seguro? Esto sobrescribir├í tus datos locales con los de la nube.')
    ) {
      return;
    }

    setIsRestoring(true);
    try {
      const cloudData = await SyncService.fetchData(userId);

      if (!cloudData) {
        setToast({
          isOpen: true,
          title: 'Sin datos',
          message: 'No se encontraron datos en la nube para este usuario.',
        });
        return;
      }

      // Restore all states
      if (cloudData.tasks)
        setTasks(cloudData.tasks.map((t: any) => ({ ...t, date: new Date(t.date) })));
      if (cloudData.habits)
        setHabits(
          cloudData.habits.map((h: any) => ({
            ...h,
            createdAt: new Date(h.createdAt),
            archivedAt: h.archivedAt ? new Date(h.archivedAt) : undefined,
          })),
        );
      if (cloudData.logs)
        setLogs(cloudData.logs.map((l: any) => ({ ...l, createdAt: new Date(l.createdAt) })));
      if (cloudData.objectives)
        setObjectives(
          cloudData.objectives.map((o: any) => ({
            ...o,
            createdAt: new Date(o.createdAt),
            deadline: o.deadline ? new Date(o.deadline) : undefined,
          })),
        );
      if (cloudData.closedDays)
        setClosedDays(
          cloudData.closedDays.map((d: any) => ({ ...d, closedAt: new Date(d.closedAt) })),
        );
      if (cloudData.weeklyInsights)
        setWeeklyInsights(
          cloudData.weeklyInsights.map((i: any) => ({
            ...i,
            generatedAt: new Date(i.generatedAt),
          })),
        );
      if (cloudData.stats) setStats(cloudData.stats);

      setToast({
        isOpen: true,
        title: 'Restauraci├│n Exitosa',
        message: 'Tus datos han sido recuperados.',
      });
    } catch (error) {
      console.error('Restore failed', error);
      setToast({
        isOpen: true,
        title: 'Error de Restauraci├│n',
        message: 'No se pudo recuperar los datos del servidor.',
      });
    } finally {
      setIsRestoring(false);
    }
  };

  // Auto-sync effect
  useEffect(() => {
    if (!import.meta.env.VITE_SUPABASE_URL) return;

    const timer = setTimeout(() => {
      const allData = { tasks, habits, logs, objectives, closedDays, weeklyInsights, stats };
      SyncService.syncData(userId, allData).catch(console.error);
    }, 10000); // Sync after 10 seconds of inactivity

    return () => clearTimeout(timer);
  }, [tasks, habits, logs, objectives, closedDays, weeklyInsights, stats, userId]);

  return { isSyncing, isRestoring, handleSync, handleRestore };
}

