export const migrationService = {
  async migrateLocalToCloud(userId: string) {
    console.log('Starting migration for user:', userId);

    // 1. Migrate Profile & Stats
    const userStorage = localStorage.getItem('iterum_user_storage');
    if (userStorage) {
      const { state } = JSON.parse(userStorage);
      if (state.stats) {
        await dbService.updateProfile(userId, state.stats);
        console.log('Profile migrated');
      }
    }

    // 2. Migrate Habits
    const habitStorage = localStorage.getItem('iterum_habits_storage');
    if (habitStorage) {
      const { state } = JSON.parse(habitStorage);
      if (state.habits && state.habits.length > 0) {
        for (const habit of state.habits) {
          const { id, createdAt, ...habitData } = habit;
          const newHabit = await dbService.createHabit(userId, habitData);

          // Migrate logs for this habit
          if (state.logs) {
            const habitLogs = state.logs.filter((l: any) => l.habitId === id);
            for (const log of habitLogs) {
              const { id: logId, createdAt: logCreated, ...logData } = log;
              await dbService.upsertHabitLog(userId, { ...logData, habitId: newHabit.id });
            }
          }
        }
        console.log('Habits and logs migrated');
      }
    }

    // 3. Migrate Tasks
    const taskStorage = localStorage.getItem('planner_tasks');
    if (taskStorage) {
      const { state } = JSON.parse(taskStorage);
      if (state.tasks && state.tasks.length > 0) {
        for (const task of state.tasks) {
          const { id, createdAt, ...taskData } = task;
          await dbService.createTask(userId, taskData);
        }
        console.log('Tasks migrated');
      }
    }

    // 4. Migrate Objectives
    const objectiveStorage = localStorage.getItem('iterum_objectives_storage');
    if (objectiveStorage) {
      const { state } = JSON.parse(objectiveStorage);
      if (state.objectives && state.objectives.length > 0) {
        for (const objective of state.objectives) {
          const { id, createdAt, ...objData } = objective;
          await dbService.createObjective(userId, objData);
        }
        console.log('Objectives migrated');
      }
    }

    console.log('Migration completed successfully');
  }
};

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

export const supabase =
  supabaseUrl && supabaseAnonKey ? createClient(supabaseUrl, supabaseAnonKey) : null;

/**
 * Basic service to handle data synchronization
 */
export class SyncService {
  static async syncData(userId: string, data: any) {
    if (!supabase) return null;

    const { error } = await supabase.from('user_data').upsert({
      user_id: userId,
      payload: data,
      updated_at: new Date().toISOString(),
    });

    if (error) {
      console.error('Sync failed:', error);
      throw error;
    }
  }

  static async fetchData(userId: string) {
    if (!supabase) return null;

    const { data, error } = await supabase
      .from('user_data')
      .select('payload')
      .eq('user_id', userId)
      .single();

    if (error && error.code !== 'PGRST116') {
      // PGRST116 is "no rows found"
      console.error('Fetch failed:', error);
      throw error;
    }

    return data?.payload || null;
  }
}

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { format } from 'date-fns';
import { Habit, HabitLog } from '../types';
import { dbService } from '../services/dbService';
import { useUserStore } from './useUserStore';

interface HabitState {
  habits: Habit[];
  logs: HabitLog[];
  loadHabits: (userId: string) => Promise<void>;
  loadLogs: (userId: string) => Promise<void>;
  addHabit: (habitData: Omit<Habit, 'id' | 'isActive' | 'createdAt'>) => void;
  updateHabit: (id: string, updates: Partial<Habit>) => void;
  deleteHabit: (id: string) => void;
  toggleHabitLog: (habitId: string, date: Date, value?: number, note?: string) => void;
  setHabits: (habits: Habit[]) => void;
  setLogs: (logs: HabitLog[]) => void;
}

export const useHabitStore = create<HabitState>()(
  persist(
    (set, get) => ({
      habits: [],
      logs: [],

      loadHabits: async (userId) => {
        try {
          const habits = await dbService.getHabits(userId);
          set({ habits: habits.map((h: any) => ({ ...h, createdAt: new Date(h.created_at) })) });
        } catch (error) {
          console.error('Failed to load habits:', error);
        }
      },

      loadLogs: async (userId) => {
        try {
          const logs = await dbService.getHabitLogs(userId);
          set({ logs: logs.map((l: any) => ({ ...l, createdAt: new Date(l.created_at) })) });
        } catch (error) {
          console.error('Failed to load logs:', error);
        }
      },

      addHabit: (habitData) => {
        const userId = useUserStore.getState().userId;
        const newHabit: Habit = {
          ...habitData,
          id: crypto.randomUUID(),
          isActive: true,
          createdAt: new Date(),
        };

        set((state) => ({ habits: [...state.habits, newHabit] }));

        if (userId) {
          dbService.createHabit(userId, habitData).catch(console.error);
        }
      },

      updateHabit: (id, updates) => {
        const userId = useUserStore.getState().userId;
        set((state) => ({
          habits: state.habits.map((h) => (h.id === id ? { ...h, ...updates } : h)),
        }));

        if (userId) {
          dbService.updateHabit(userId, id, updates).catch(console.error);
        }
      },

      deleteHabit: (id) => {
        const userId = useUserStore.getState().userId;
        set((state) => ({
          habits: state.habits.filter((h) => h.id !== id),
          logs: state.logs.filter((l) => l.habitId !== id),
        }));

        if (userId) {
          dbService.deleteHabit(userId, id).catch(console.error);
        }
      },

      toggleHabitLog: (habitId, date, value, note) => {
        const userId = useUserStore.getState().userId;
        const dateStr = format(date, 'yyyy-MM-dd');

        set((state) => {
          const existingLog = state.logs.find((l) => l.habitId === habitId && l.date === dateStr);
          if (existingLog) {
            if (existingLog.completed && !value && !note) {
              if (userId) dbService.deleteHabitLog(userId, existingLog.id).catch(console.error);
              return { logs: state.logs.filter((l) => l.id !== existingLog.id) };
            } else {
              const updatedLog = {
                ...existingLog,
                completed: true,
                value: value ?? existingLog.value,
                note: note ?? existingLog.note,
              };
              if (userId) dbService.upsertHabitLog(userId, updatedLog).catch(console.error);
              return {
                logs: state.logs.map((l) => (l.id === existingLog.id ? updatedLog : l)),
              };
            }
          } else {
            const newLog: HabitLog = {
              id: crypto.randomUUID(),
              habitId,
              date: dateStr,
              completed: true,
              value,
              note,
              createdAt: new Date(),
            };
            if (userId) dbService.upsertHabitLog(userId, newLog).catch(console.error);
            return { logs: [...state.logs, newLog] };
          }
        });
      },
      setHabits: (habits) => set({ habits }),
      setLogs: (logs) => set({ logs }),
    }),
    {
      name: 'iterum_habits_storage',
      storage: createJSONStorage(() => localStorage),
      onRehydrateStorage: () => (state) => {
        if (state) {
          state.habits = state.habits.map((h: any) => ({
            ...h,
            createdAt: new Date(h.createdAt),
            archivedAt: h.archivedAt ? new Date(h.archivedAt) : undefined,
          }));
          state.logs = state.logs.map((l: any) => ({
            ...l,
            createdAt: new Date(l.createdAt),
          }));
        }
      },
    },
  ),
);

